window.__QUIZ_DATA__=[{"id":"objective>Geography>1999>1","subject":"Geography","year":"1999","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : MAP WORK","question":"Use the map of KENECHI DISTRICT to answer the question       What is the scale of the map in Representative Fraction (R.F)?","images":["data:image/png;base64,"],"options":{"A":"1:200,000","B":"1:100,000","C":"1:50.000","D":"1:20,000"},"answer":"A","explanation":"From the linear scale on the map, 1cm represents 2km. Recall that 1cm to 1km on the linear scale is easily convertible to 1:100,000  on the representative fraction (R.F).","marks":"1","difficulty":"2"},{"id":"objective>Geography>1999>2","subject":"Geography","year":"1999","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : MAP WORK","question":"Use the map of KENECHI DISTRICT to answer the question     The actual distance of KENECHI from Abia along the road is approximately","images":["data:image/png;base64,"],"options":{"A":"5.5 cm","B":"5.5 km","C":"11.0 cm","D":"11.0 km"},"answer":"D","explanation":"By using a piece of thread, the distance of Kenechi from Abia along the road is 5.5cm. Since the scale of the map is 1cm to 2km, 5.5cm implies 11.0km on the ground.","marks":"1","difficulty":"2"},{"id":"objective>Geography>1999>3","subject":"Geography","year":"1999","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : MAP WORK","question":"Use the map of KENECHI DISTRICT to answer the question     If the map is enlarged to twice its size, what will be the scale of the enlarged map ?","images":["data:image/png;base64,"],"options":{"A":"1: 50,000","B":"1:100,000","C":"1:150,000","D":"1:200,000"},"answer":"B","explanation":"To get the new scale of the enlarged map, multiply the old scale by 2.  1/200000 x 2=2/200000=1/100000  Hence, the new scale for the enlarged map is 1:100000","marks":"1","difficulty":"2"},{"id":"objective>Geography>1999>4","subject":"Geography","year":"1999","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : MAP WORK","question":"Use the map of KENECHI DISTRICT to answer the question     The direction of the plantation at KENECHI from Dabu is","images":["data:image/png;base64,"],"options":{"A":"N.10oE","B":"N.45oE","C":"S.45oW","D":"N.50oW"},"answer":"B","explanation":"The direction of the plantation at KENECHI from Dabu is N.45oE","marks":"1","difficulty":"2"},{"id":"objective>Geography>1999>5","subject":"Geography","year":"1999","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : MAP WORK","question":"Use the map of KENECHI DISTRICT to answer the question     The feature marked Y near the northern border of the map is called a","images":["data:image/png;base64,"],"options":{"A":"spur","B":"headland","C":"valley","D":"bridge"},"answer":"A","explanation":"The feature marked Y is called a spur. Spurs are located on highlands. They are projection of highlands into lowlands i.e the Y shape points to the lowlands.","marks":"1","difficulty":"2"},{"id":"objective>Geography>1999>6","subject":"Geography","year":"1999","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : MAP WORK","question":"Use the map of KENECHI DISTRICT to answer the question     The feature marked Z on the western part of the map near Vokote is called a","images":["data:image/png;base64,"],"options":{"A":"Ridge","B":"Scarp","C":"Pass","D":"Gap"},"answer":"C","explanation":"The feature marked Z is a pass. A pass or gap seperates two highlands at lower levels. A pass or gap is also a col but is found at lower parts of highlands","marks":"1","difficulty":"2"},{"id":"objective>Geography>1999>7","subject":"Geography","year":"1999","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : MAP WORK","question":"Use the map of KENECHI DISTRICT to answer the question     The feature marked A to B represents a","images":["data:image/png;base64,"],"options":{"A":"dry valley","B":"inselberg","C":"Knoll","D":"Watershed"},"answer":"A","explanation":"The feature marked A to B is a dry valley. A valley is a lowland between two highlands. Valleys are represented with V-shaped contour lines with the apex of the V-shape pointing towards the highlands. When a valley does not contain water it is called a dry valley.","marks":"1","difficulty":"2"},{"id":"objective>Geography>1999>8","subject":"Geography","year":"1999","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : MAP WORK","question":"Use the map of KENECHI DISTRICT to answer the question     What is the area of the plantation in Kenechi?","images":["data:image/png;base64,"],"options":{"A":"20km2","B":"16km2","C":"12km2","D":"8km2"},"answer":"D","explanation":"The area of the plantation in Kenechi is measured 8km2","marks":"1","difficulty":"2"},{"id":"objective>Geography>1999>9","subject":"Geography","year":"1999","type":"Objective","topic":"REGIONAL GEOGRAPHY OF NIGERIA : AGRICULTURE","question":"Use the map of KENECHI DISTRICT to answer the question     Which crop is best suited in the south-eastern corner of the area shown on the map?","images":["data:image/png;base64,"],"options":{"A":"Cotton","B":"Tea","C":"Cocoa","D":"Rice"},"answer":"D","explanation":"As shown on the map, rice is most suitable to be grown in the south-eastern corner of the area . This is so because, the south-eastern corner of the area is liable to flood. This results in a marshy area and rice is likely to be produced in such area","marks":"1","difficulty":"2"},{"id":"objective>Geography>1999>10","subject":"Geography","year":"1999","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : MAP WORK","question":"Use the map of KENECHI DISTRICT to answer the question     Which of the following pairs of towns are intervisible?","images":["data:image/png;base64,"],"options":{"A":"Vokote and Dabu","B":"Kenechi and Udeze","C":"Gbagada and Ketu","D":"Medu and Tiba."},"answer":"D","explanation":"Medu and Tiba are intervisible because the contour lines between them are at the same point and no higher contour lines exist between them.","marks":"1","difficulty":"2"},{"id":"objective>Geography>1999>11","subject":"Geography","year":"1999","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : TRADE","question":"Use the figure below to answer the question. Figure (in metric tons) World value of major export commodities 1950      The Figure is a","images":["data:image/png;base64,"],"options":{"A":"wind rose","B":"pie chart","C":"proportional circle","D":"divided proportional circle"},"answer":"B","explanation":"The figure 1 shows the distribution in sectorial portion. It is a pie chart","marks":"1","difficulty":"2"},{"id":"objective>Geography>1999>12","subject":"Geography","year":"1999","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : TRADE","question":"Use the figure below to answer the question. Figure (in metric tons) World value of major export commodities 1950    The total value of the world's export commodities represented in the  Fig.  is","images":["data:image/png;base64,"],"options":{"A":"1,000,000 metric tons","B":"1,250,000 metric tons.","C":"2,678,000 metric tons","D":"2,780,000 metric tons"},"answer":"D","explanation":"The total value= 660000 + 420000 + 530000 + 580000 + 590000 = 2,780,000 metric tons","marks":"1","difficulty":"2"},{"id":"objective>Geography>1999>13","subject":"Geography","year":"1999","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : TRADE","question":"Use the figure below to answer the question. Figure (in metric tons) World value of major export commodities 1950    What percentage of the world's export commodities in the Figure  is represented by crude oil?","images":["data:image/png;base64,"],"options":{"A":"54.4%.","B":"42.8%.","C":"32.47%.","D":"23.74%."},"answer":"D","explanation":"percentage of the world's export commodities represented by crude oil = export commodities of crude oil/Total value of export commodities X 100%=660000/2780000 X 100% = 23.74%","marks":"1","difficulty":"2"},{"id":"objective>Geography>1999>14","subject":"Geography","year":"1999","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : STATISTICAL MAPS AND DIAGRAMS","question":"Use the figure below to answer the question. Figure (in metric tons) World value of major export commodities 1950    In which of the following ways can the data shown in  the Figure  be represented?","images":["data:image/png;base64,"],"options":{"A":"Simple bar graph","B":"Proportional circle","C":"Dot map.","D":"Chloropleth"},"answer":"B","explanation":"Proportional circles are used to illustrate population distribution and/or economic production and distribution, Since figure 1 shows the world value of major export commodities, a proportional circle can be used to represent the data shown in figure 1.","marks":"1","difficulty":"2"},{"id":"objective>Geography>1999>15","subject":"Geography","year":"1999","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ROCKS","question":"Coal and mineral oil are usually found embedded in","images":[],"options":{"A":"crystalline rocks","B":"igneous rocks","C":"metamorphic rocks","D":"sedimentary rocks."},"answer":"D","explanation":"Coal and mineral oil are usually found embedded in sedimentary rocks. Sedimentary rocks are formed from the accumulation of sediments, which are compacted and cemented over time. This process often traps organic material, which can turn into coal or oil under the right conditions.","marks":"1","difficulty":"1"},{"id":"objective>Geography>1999>16","subject":"Geography","year":"1999","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : WEATHER AND CLIMATE","question":"When the sun is overhead at 231/2 oS, all places at 231/2 oN  experience","images":[],"options":{"A":"total day light","B":"shorter days and longer nights.","C":"longer days and shorter nights","D":"equal days and nights"},"answer":"B","explanation":"When the sun is overhead at the Tropic of Capricorn (231/2 oS), all places at the Tropic of Cancer (231/2 oN) experience shorter days and longer nights.","marks":"1","difficulty":"2"},{"id":"objective>Geography>1999>17","subject":"Geography","year":"1999","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ELEMENTS OF PHYSICAL GEOGRAPHY","question":"The earth lies between","images":[],"options":{"A":"Mercury and Venus","B":"Mars and Jupiter","C":"Venus and Mars","D":"Jupiter and Saturn"},"answer":"C","explanation":"In the solar system, after Venus comes the Earth and then Mars. So, the earth lies between Venus and Mars","marks":"1","difficulty":"1"},{"id":"objective>Geography>1999>18","subject":"Geography","year":"1999","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : MAP WORK","question":"If A is located on latitude 6 oN and B on latitude 12 oN, what is the distance between the two places?","images":[],"options":{"A":"1.998km","B":"777km","C":"666km","D":"66.6km"},"answer":"C","explanation":"For two given places on the earth's surface, the distance, d between them is given by \u229d/360 X 2\u03a0R.  Where \u229d is the angular difference between the two places.  \u03a0 = 22/7  R is the radius of the earth. Take R =6371Km  Angular difference between A and B= 12 - 6 = 6o  d=6o/360o x 2 x 22/7 x 6371  d = 666Km. Hence the distance between A and B is approximately 666Km.","marks":"1","difficulty":"2"},{"id":"objective>Geography>1999>19","subject":"Geography","year":"1999","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : TECTONIC PROCESSES","question":"The separation of ancient Gondwana land into different land masses was caused mainly by","images":[],"options":{"A":"isostatic shift","B":"earthquakes","C":"vulcanicity","D":"continental drift"},"answer":"D","explanation":"The breakup of Gondwana occured in stages. Some 180 million years ago, in the Jurassic period, the Western half of Gondwana(Africa and South America) separated from the Eastern half (Madagascar, India, Australia and Antartica) due to plate tectonic theory which explains the continental drift","marks":"1","difficulty":"3"},{"id":"objective>Geography>1999>20","subject":"Geography","year":"1999","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ROCKS","question":"Marble and Schist are examples of","images":[],"options":{"A":"sedimentary rocks","B":"volcanic rocks","C":"metamorphic rocks","D":"plutonic rocks"},"answer":"C","explanation":"Marble and Schist are examples of metamorphic rocks. Metamorphic rocks arise from the transformation of existing rock types, in a process called metamorphism, which means 'change in form'. The original rock (protolith) is subjected to heat and pressure, causing profound physical or chemical change.","marks":"1","difficulty":"1"},{"id":"objective>Geography>1999>21","subject":"Geography","year":"1999","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : DENUDATIONAL PROCESSES","question":"In which of the following regions would exfoliation commonly occur?","images":[],"options":{"A":"Regions with high temperatures and large amount of rainfall","B":"Semi-arid regions with large diurnal range of temperature","C":"Regions with large amounts of limestone and chalk","D":"Regions with luxuriant vegetation cover"},"answer":"B","explanation":"One of the agents of physical weathering is temperature changes. It is common in arid regions like hot deserts where rocks are exposed to blazing sun during the day. Exfoliation is the process involved in the peeling off of the rock surface as a result of the alternate expansion and contraction of the rock. It would occur commonly in Semi-arid regions with large diurnal range of temperature.","marks":"1","difficulty":"2"},{"id":"objective>Geography>1999>22","subject":"Geography","year":"1999","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : DENUDATIONAL PROCESSES","question":"A steep-side feature with vertical bands of alternate hard arid soft rocks, aligned in the direction of the prevailing winds is","images":[],"options":{"A":"Mesa","B":"Zeugen","C":"Yardang","D":"Rock pedestal"},"answer":"C","explanation":"Yardangs are steep-side feature with vertical bands of alternate hard arid soft rocks, aligned in the direction of the prevailing wind.","marks":"1","difficulty":"2"},{"id":"objective>Geography>1999>23","subject":"Geography","year":"1999","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : HYDROSPHERE","question":"All the following condition are favourable for the formation of delta except","images":[],"options":{"A":"presence of large lakes in ther river course","B":"availability of adequate sediments","C":"absence of strong current at the river mouth","D":"presence of sheltered coast"},"answer":"A","explanation":"The presence of large lakes in ther river course won't favour the formation of deltas because large lakes are not shallow and this will cause dissappearance of sediments into deep waters.","marks":"1","difficulty":"2"},{"id":"objective>Geography>1999>24","subject":"Geography","year":"1999","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : TECTONIC PROCESSES","question":"Which of the following is responsible for the formation of block mountains?","images":[],"options":{"A":"Faulting","B":"Sedimentation","C":"Folding","D":"Deposition"},"answer":"A","explanation":"Block mountains are formed when the earth cracks due to faulting. Faulting may result from tensional forces or compressional forces. Tensional forces are those that tend to pull the earth's crust apart and they result in a normal fault while compressional forces are those that shorten the crust to produce a reverse or thrust fault.","marks":"1","difficulty":"2"},{"id":"objective>Geography>1999>25","subject":"Geography","year":"1999","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : HYDROSPHERE","question":"The feature commonly found along the lower course of a river are","images":[],"options":{"A":"windgaps","B":"rapids","C":"waterfalls","D":"meanders"},"answer":"D","explanation":"Meanders results when rivers are unable to flow straight due to low gravity, sluggish movement of water and heavy loads. The winding course or curve that develops along the course of the river is called Meander.","marks":"1","difficulty":"2"},{"id":"objective>Geography>1999>26","subject":"Geography","year":"1999","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : WEATHER AND CLIMATE","question":"Which of the following ocean currents lowers the temperature of the adjacent coastland ?","images":[],"options":{"A":"Benguela current","B":"Kuro siwo current","C":"Brazillian current","D":"Agulhas current"},"answer":"A","explanation":"The Benguela current lowers the temperature of the adjacent coastland. The Benguela current is an ocean current of the Atlantic ocean.","marks":"1","difficulty":"2"},{"id":"objective>Geography>1999>27","subject":"Geography","year":"1999","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : WEATHER AND CLIMATE","question":"Use the information in the table below to answer the question  monthJFMAMJJASONDtemp (oC)212426323129272527272635precipitation(mm)00313711212113021381200Table: Temperature and rainfall data for Station Z.","images":[],"options":{"A":"25oC","B":"27.5oC","C":"28.5oC","D":"33oC"},"answer":"B","explanation":"Mean Temperature of station Z =Annual Temperature of station Z /Number of months.  21+24+26+32+31+29+27+25+27+27+26+35/12=220/12=27.5oC  Hence, the mean  monthly temperature of station Z is 27.5oC.","marks":"1","difficulty":"2"},{"id":"objective>Geography>1999>28","subject":"Geography","year":"1999","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : WEATHER AND CLIMATE","question":"Use the information in the table below to answer the question  monthJFMAMJJASONDtemp (oC)212426323129272527272635precipitation(mm)00313711212113021381200Table: Temperature and rainfall data for Station Z.  How many months of dry season has the Station?","images":[],"options":{"A":"4","B":"5","C":"7","D":"8"},"answer":"A","explanation":"The dry season are seasons with no precipitation.  Dry season occurs in 4months i.e January, February, November and December=J,F,N and D","marks":"1","difficulty":"2"},{"id":"objective>Geography>1999>29","subject":"Geography","year":"1999","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : WEATHER AND CLIMATE","question":"Use the information in the table below to answer the question  monthJFMAMJJASONDtemp (oC)212426323129272527272635precipitation(mm)00313711212113021381200Table: Temperature and rainfall data for Station Z.  The annual rainfall amount for the station is","images":[],"options":{"A":"72.6 mm","B":"299 mm","C":"302 mm","D":"871 mm"},"answer":"D","explanation":"The annual rainfall amount is calculated by adding up the rainfall for each month. From the table, if we add up the precipitation for each month, we get 871mm. Therefore, the annual rainfall amount for the station is 871mm.","marks":"1","difficulty":"2"},{"id":"objective>Geography>1999>30","subject":"Geography","year":"1999","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : WEATHER AND CLIMATE","question":"If the temperature of sea level is 30oC the temperature of the air at a height of 2000 meters will be approximately","images":[],"options":{"A":"25oC","B":"20oC","C":"18oC","D":"10oC"},"answer":"C","explanation":"Recall, a regular air temperature decreases with an average rate of 0.65oC for every 100 metres of ascent. The rate is called the lapse rate.  Lapse Rate =6.5oC per 1000 metres of ascent  Therefore, 2000m of ascent = 6.5 X 2000/1000=6.5 X 2 =13oC  Since the temperature at sea level is 30oC, then the temperature at the height of 2000metres= 30-13=17oC","marks":"1","difficulty":"2"},{"id":"objective>Geography>1999>31","subject":"Geography","year":"1999","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ELEMENTS OF PHYSICAL GEOGRAPHY","question":"The instrument used for measuring wind velocity is called","images":[],"options":{"A":"a barometer","B":"a wind vane","C":"a hygrometer","D":"an anemometer"},"answer":"D","explanation":"The speed of the wind is measured by an instrument called the Anemometer while the wind vane measures the wind direction","marks":"1","difficulty":"1"},{"id":"objective>Geography>1999>32","subject":"Geography","year":"1999","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : SOIL","question":"Which of the following soil types that support the tropical rainforest?","images":[],"options":{"A":"Chernozem","B":"Podsol","C":"Leterite","D":"Tenarosa"},"answer":"B","explanation":"The Podsol is a group of zonal soils that develop in a moist climate especially the tropical rainforest and have an organic-mineral layer above a light gray leached layer resting on a dark horizon that is marked by illuviation and enriched with amorphous clay","marks":"1","difficulty":"2"},{"id":"objective>Geography>1999>33","subject":"Geography","year":"1999","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : DENUDATIONAL PROCESSES","question":"The removal of soil or rocks particles by wind or running water is called","images":[],"options":{"A":"weathering","B":"leaching","C":"denudation","D":"erosion"},"answer":"D","explanation":"Erosion is the process of eroding or being eroded by wind, water, or other natural agents. It is the action of surface processes (such as water flow or wind) that removes soil, rock, or dissolved material from one location on the Earth's crust, and then transports it to another location.","marks":"1","difficulty":"2"},{"id":"objective>Geography>1999>34","subject":"Geography","year":"1999","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ENVIRONMENTAL RESOURCES","question":"Which of the following natural resources is non-renewable?","images":[],"options":{"A":"Soil","B":"Vegetation","C":"Wildlife","D":"Minerals"},"answer":"D","explanation":"Non-renewable resources are those that do not replenish in a short period of time. Minerals are formed over millions of years and once extracted, they cannot be replaced in a human timescale. Therefore, they are considered non-renewable.","marks":"1","difficulty":"2"},{"id":"objective>Geography>1999>35","subject":"Geography","year":"1999","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : WEATHER AND CLIMATE","question":"Koppen's wet tropical (AF) type of climate is experienced in West Africa in","images":[],"options":{"A":"Accra","B":"Monrovia","C":"Dakar","D":"Kano"},"answer":"A","explanation":"The Koppen's wet tropical (AF) type of climate is experienced in Ghana(Accra), a part of West Africa.","marks":"1","difficulty":"3"},{"id":"objective>Geography>1999>36","subject":"Geography","year":"1999","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : WEATHER AND CLIMATE","question":"Equatorial lowlands usually experience","images":[],"options":{"A":"very early morning rains","B":"heavy thunder rains in the afternoons","C":"strong winds","D":"cold nights"},"answer":"B","explanation":"Equatorial lowlands usually experience heavy thunder rains in the afternoons because as the air rises, it cools and cannot hold as much water vapour, so the water condenses, forms cloud and it rains, this is known as convectional rainfall.","marks":"1","difficulty":"2"},{"id":"objective>Geography>1999>37","subject":"Geography","year":"1999","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : VEGETATION","question":"Vegetation resources can be utilized by man for all the following except","images":[],"options":{"A":"food","B":"habitat","C":"timber","D":"medicine"},"answer":"B","explanation":"All except habitat are the utilization of vegetation resources by man. Provision of habitat is an utilization of land resources.","marks":"1","difficulty":"2"},{"id":"objective>Geography>1999>38","subject":"Geography","year":"1999","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ENVIRONMENTAL PROBLEMS/ HAZARDS","question":"Which of the following forms of pollution is the least harzardous to man ?","images":[],"options":{"A":"Toxic waste disposed in rivers","B":"The use of chemicals for fishing","C":"Flaring of gas from refineries","D":"A sound of 50 decibels in the air"},"answer":"D","explanation":"A sound of 50 decibels in the air falls in the category of sound of normal audibility. It does not cause harzard to man.","marks":"1","difficulty":"3"},{"id":"objective>Geography>1999>39","subject":"Geography","year":"1999","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : INDUSTRY","question":"Industries are classified as","images":[],"options":{"A":"primary, manufacturing and secondary","B":"cocoa processing, mining and furnitur making","C":"primary, manufcaturing and tertiary","D":"fishing, mining and food processing"},"answer":"C","explanation":"Industries are classified into primary, secondary, and tertiary. Primary industries involve the extraction of raw materials (like mining), secondary industries involve manufacturing and processing of these raw materials, and tertiary industries provide services. Therefore, the correct option is 'primary, manufacturing and tertiary'.","marks":"1","difficulty":"2"},{"id":"objective>Geography>1999>40","subject":"Geography","year":"1999","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ENVIRONMENTAL RESOURCES","question":"Atmospheric resources can used for all the following except","images":[],"options":{"A":"power supply","B":"sifting of grains","C":"housing","D":"communication"},"answer":"C","explanation":"Atmospheric resources such as wind and solar can be used for power supply and communication. However, they cannot be used for housing. Housing is a physical structure that requires materials like bricks, wood, cement, etc. Atmospheric resources cannot provide these materials.","marks":"1","difficulty":"3"},{"id":"objective>Geography>1999>41","subject":"Geography","year":"1999","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : INDUSTRY","question":"The manufacturing of textiles and garments is most popular in","images":[],"options":{"A":"South Korea","B":"Japan","C":"Taiwan","D":"Thailand"},"answer":"D","explanation":"The manufacturing of textiles and garments is most popular in Thailand. Thailand currently has around 4,500 manufacturers employing almost one million workers in the texile and garment manufacturing industries.","marks":"1","difficulty":"2"},{"id":"objective>Geography>1999>42","subject":"Geography","year":"1999","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : SETTLEMENT","question":"A megalopolis is a","images":[],"options":{"A":"modern town specially developed to accommodate urban people wishing to reside outside the city","B":"new city developed to accommodate workers from neighbouring industrial centres","C":"town that has grown to engulf nearby rural settlements","D":"continuous amalgamation of a series of cities"},"answer":"D","explanation":"A megalopolis is a large area with big cities, it is linked by communication network, it has a continuous stretch of land and it contains several millions of people.","marks":"1","difficulty":"3"},{"id":"objective>Geography>1999>43","subject":"Geography","year":"1999","type":"Objective","topic":"REGIONAL GEOGRAPHY OF NIGERIA : ISSUES ON DEVELOPMENT AND ENVIRONMENTAL CONCERNS","question":"The most common environmental problem in the Niger Delta is","images":[],"options":{"A":"deforestation","B":"aridity","C":"coastal flooding","D":"vulcanicity"},"answer":"C","explanation":"The Niger Delta is faced with a major problem of coastal flooding. coastal flooding has led to the destruction of various important properties in the Niger Delta.","marks":"1","difficulty":"2"},{"id":"objective>Geography>1999>44","subject":"Geography","year":"1999","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : TRANSPORTATION","question":"The likely harzards to shipping at the North American end of the North Atlantic sea route are","images":[],"options":{"A":"waterfalls and rapids","B":"fog and iceberg","C":"submarine ridges and trenches","D":"shallow inlets and weeds"},"answer":"B","explanation":"The likely hazards to shipping at the North American end of the North Atlantic sea route are fog and iceberg. The North Atlantic sea route is known for its cold climate, which can lead to the formation of icebergs. Fog is also common in this region, reducing visibility for ships.","marks":"1","difficulty":"3"},{"id":"objective>Geography>1999>45","subject":"Geography","year":"1999","type":"Objective","topic":"REGIONAL GEOGRAPHY OF NIGERIA : RESOURCES","question":"The bulk of Nigeria's timber is exploited from the","images":[],"options":{"A":"mountain vegetation","B":"rainforest","C":"Guinea savanna","D":"fresh water swamp forest"},"answer":"B","explanation":"The rainforest serves the production of timber in Nigeria. It is found in the Southern part of Nigeria in Benin, Sapele, Akure, Ibadan, Abeokuta, Aba etc. It provides tropical hardwood like Iroko, obeche, mahogany etc. timber for construction purposes.","marks":"1","difficulty":"2"},{"id":"objective>Geography>1999>46","subject":"Geography","year":"1999","type":"Objective","topic":"REGIONAL GEOGRAPHY OF NIGERIA : TRADE","question":"Nigeria's major trading partners include","images":[],"options":{"A":"Britain, USA, Germany and Japan","B":"Britain, Ghana, Japan and South Africa","C":"Belgium , Germany, Japan and Liberia","D":"USA, Belgium,The Gambia and Japan"},"answer":"A","explanation":"Nigeria's major trading partners are countries with which it has significant import and export relationships. These countries include Britain, USA, Germany and Japan. These countries are major global economies and Nigeria has significant trade relationships with them, especially in the areas of oil and gas, agriculture, and manufacturing.","marks":"1","difficulty":"2"},{"id":"objective>Geography>1999>47","subject":"Geography","year":"1999","type":"Objective","topic":"REGIONAL GEOGRAPHY OF AFRICA : AFRICA ON BROAD OUTLINE","question":"The Akwapim-Togo Ridge is a continuation of the","images":[],"options":{"A":"Guinea highlands","B":"Bandiagara escarpment","C":"Plateau of Burkina Faso","D":"Uplands of Western Nigeria"},"answer":"A","explanation":"The Akwapim-Togo Ridge is a continuation of the Guinea highlands. It is a narrow belt of ridges and hills in Ghana, Western Africa. They extend in a southwest-northwest line for about 200miles from the Densu River mouth(near Accra) on the Atlantic coast to the boundary with Togo.","marks":"1","difficulty":"2"},{"id":"objective>Geography>1999>48","subject":"Geography","year":"1999","type":"Objective","topic":"REGIONAL GEOGRAPHY OF NIGERIA : TRANSPORTATION","question":"The Lagas-Kano railway crosses the River Niger at","images":[],"options":{"A":"Makurdi","B":"Kontagora","C":"Jebba","D":"Lokoja"},"answer":"C","explanation":"The Lagos-Kano railway crosses the River Niger at Jebba. Jebba is a city in Nigeria located on the River Niger and it is a key crossing point for the Lagos-Kano railway, which is a major transportation route in Nigeria.","marks":"1","difficulty":"2"},{"id":"objective>Geography>1999>49","subject":"Geography","year":"1999","type":"Objective","topic":"REGIONAL GEOGRAPHY OF AFRICA : AFRICA ON BROAD OUTLINE","question":"Most of the copper exported from the Democratic Republic of Congo (Zaire) is produced in and around","images":[],"options":{"A":"Kinshasa","B":"Lubumbashi","C":"Kabinda","D":"Kissangani"},"answer":"B","explanation":"Lubumbashi is the center of mining in the Democratic Republic of Congo, which is rich in copper. Therefore, most of the copper exported from the country is produced in and around Lubumbashi.","marks":"1","difficulty":"2"},{"id":"objective>Geography>1999>50","subject":"Geography","year":"1999","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : INDUSTRY","question":"The greatest advantage of pereninnial irrigation is that","images":[],"options":{"A":"two or three crops can be produced in a year from the same piece of land","B":"it makes it possible to irrigate larger areas","C":"much silt is trapped and this helps to enrich the soil","D":"it allows water to be held on the land for several weeks"},"answer":"A","explanation":"The greatest advantage of pereninnial irrigation is that two or three crops can be produced in a year from the same piece of land","marks":"1","difficulty":"2"}];